// Approach 1: Sort and compare (concise)
function isAnagram(a, b) {
  const norm = (s) => s.toLowerCase().split('').sort().join('');
  return norm(a) === norm(b);
}

// Approach 2: Frequency counter (faster for long strings)
function isAnagramFast(a, b) {
  if (a.length !== b.length) return false;
  const counts = new Map();
  for (const ch of a.toLowerCase()) {
    counts.set(ch, (counts.get(ch) || 0) + 1);
  }
  for (const ch of b.toLowerCase()) {
    if (!counts.has(ch)) return false;
    counts.set(ch, counts.get(ch) - 1);
    if (counts.get(ch) < 0) return false;
  }
  return true;
}

// Recursive
function factorial(n) {
  if (n <= 1) return 1;
  return n * factorial(n - 1);
}

// Iterative (no stack overflow risk)
function factorialIter(n) {
  let result = 1;
  for (let i = 2; i <= n; i++) result *= i;
  return result;
}

// Bottom-up, O(n) time, O(1) space
function fib(n) {
  if (n <= 1) return n;
  let prev = 0, curr = 1;
  for (let i = 2; i <= n; i++) {
    [prev, curr] = [curr, prev + curr];
  }
  return curr;
}

// With memoization (top-down)
const memo = new Map([[0, 0], [1, 1]]);
function fibMemo(n) {
  if (memo.has(n)) return memo.get(n);
  const result = fibMemo(n - 1) + fibMemo(n - 2);
  memo.set(n, result);
  return result;
}

function binarySearch(nums, target) {
  let left = 0, right = nums.length - 1;
  while (left <= right) {
    const mid = (left + right) >> 1;  // bit-shift for integer division
    if (nums[mid] === target) return mid;
    if (nums[mid] < target) left = mid + 1;
    else right = mid - 1;
  }
  return -1;
}

// Simple Set approach
function dedupe(arr) {
  return [...new Set(arr)];
}

// Preserve order, filter manually (for objects you can't put in Set)
function dedupeBy(arr, keyFn = (x) => x) {
  const seen = new Set();
  return arr.filter((item) => {
    const key = keyFn(item);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

