function capitaliseWords(str) {
  return str
    .split(' ')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
}

function charFreq(str) {
  const freq = {};
  for (const ch of str) {
    freq[ch] = (freq[ch] || 0) + 1;
  }
  return freq;
}

// Map version (works when keys aren't strings)
function charFreqMap(str) {
  const freq = new Map();
  for (const ch of str) {
    freq.set(ch, (freq.get(ch) || 0) + 1);
  }
  return freq;
}

// String approach
function sumDigits(n) {
  return String(n).split('').reduce((sum, d) => sum + Number(d), 0);
}

// Math approach (no string conversion)
function sumDigitsMath(n) {
  let sum = 0;
  while (n > 0) {
    sum += n % 10;
    n = Math.floor(n / 10);
  }
  return sum;
}
